/* ===== Helper: flatten tree for graph ===== */
function flattenBlogTree(nodes, result) {
  nodes.forEach(function(node) {
    if (node.file) {
      result.push(node);
    }
    if (node.children) {
      flattenBlogTree(node.children, result);
    }
  });
  return result;
}

/* ===== Code-editor style file tree navigation ===== */
(function buildBlogNav() {
  var nav = document.querySelector('.blog-nav');
  if (!nav) return;

  var path = window.location.pathname;
  var inBlogDir = path.indexOf('/blog/') !== -1;
  /* Compute the file path relative to /blog/ */
  var blogIdx = path.indexOf('/blog/');
  var currentRelative = blogIdx !== -1 ? path.substring(blogIdx + 6) : '';

  /* prefix for links: from blog index page use 'blog/', from within blog dirs compute relative */
  function getHref(file) {
    if (!inBlogDir) return 'blog/' + file;
    /* Compute relative path from current page to target file */
    var curParts = currentRelative.split('/');
    curParts.pop(); /* remove filename */
    var tgtParts = file.split('/');
    /* Find common prefix */
    var common = 0;
    while (common < curParts.length && common < tgtParts.length - 1 && curParts[common] === tgtParts[common]) {
      common++;
    }
    var up = curParts.length - common;
    var rel = '';
    for (var i = 0; i < up; i++) rel += '../';
    rel += tgtParts.slice(common).join('/');
    return rel || tgtParts[tgtParts.length - 1];
  }

  var heading = document.createElement('h4');
  heading.textContent = 'Explorer';
  nav.appendChild(heading);

  function buildLevel(items, container, depth) {
    items.forEach(function(item) {
      if (item.children) {
        /* Folder node */
        var folder = document.createElement('div');
        folder.className = 'file-tree-folder';
        folder.style.paddingLeft = (depth * 12) + 'px';

        var btn = document.createElement('button');
        btn.className = 'file-tree-toggle';
        btn.innerHTML = '<span class="ft-chevron">&#9654;</span>' +
          '<span class="ft-icon ft-folder">&#128193;</span>' +
          '<span class="ft-label">' + item.label + '</span>';

        var childContainer = document.createElement('div');
        childContainer.className = 'file-tree-children';

        /* Check if any child is active to auto-expand */
        var hasActive = false;
        (function checkActive(nodes) {
          nodes.forEach(function(n) {
            if (n.file && currentRelative === n.file) hasActive = true;
            if (n.children) checkActive(n.children);
          });
        })(item.children);

        if (hasActive) {
          btn.classList.add('open');
          childContainer.classList.add('open');
        }

        btn.addEventListener('click', function() {
          btn.classList.toggle('open');
          childContainer.classList.toggle('open');
        });

        folder.appendChild(btn);
        container.appendChild(folder);
        container.appendChild(childContainer);
        buildLevel(item.children, childContainer, depth + 1);
      } else {
        /* File (leaf) node */
        var fileEl = document.createElement('a');
        fileEl.className = 'file-tree-file';
        fileEl.style.paddingLeft = (depth * 12 + 8) + 'px';
        fileEl.href = getHref(item.file);
        var ext = item.file.split('.').pop();
        var icon = ext === 'html' ? '&#128196;' : '&#128196;';
        fileEl.innerHTML = '<span class="ft-icon ft-file">' + icon + '</span>' +
          '<span class="ft-label">' + item.title + '</span>';

        if (currentRelative === item.file) {
          fileEl.classList.add('active');
        }
        container.appendChild(fileEl);
      }
    });
  }

  buildLevel(BLOG_TREE, nav, 0);
})();

/* Blog post: collapsible sidebar toggle */
(function blogSidebarCollapse() {
  var layout = document.querySelector('.blog-post-layout');
  var sidebar = document.querySelector('.blog-sidebar');
  if (!layout || !sidebar) return;

  var STORAGE_KEY = 'blog-sidebar-collapsed';
  var btn = document.createElement('button');
  btn.type = 'button';
  btn.className = 'sidebar-toggle';
  btn.setAttribute('aria-label', 'Toggle explorer');
  btn.setAttribute('aria-controls', 'blog-sidebar-body');
  btn.innerHTML = '<span class="st-icon" aria-hidden="true">\u00AB</span><span class="st-label">Collapse</span>';

  var body = document.createElement('div');
  body.className = 'blog-sidebar-body';
  body.id = 'blog-sidebar-body';
  while (sidebar.firstChild) body.appendChild(sidebar.firstChild);
  sidebar.appendChild(btn);
  sidebar.appendChild(body);

  function apply(collapsed) {
    layout.classList.toggle('sidebar-collapsed', collapsed);
    btn.setAttribute('aria-expanded', collapsed ? 'false' : 'true');
    btn.querySelector('.st-icon').textContent = collapsed ? '\u00BB' : '\u00AB';
    btn.querySelector('.st-label').textContent = collapsed ? '' : 'Collapse';
    btn.title = collapsed ? 'Expand explorer' : 'Collapse explorer';
  }

  var initial = false;
  try { initial = localStorage.getItem(STORAGE_KEY) === '1'; } catch (e) {}
  apply(initial);

  btn.addEventListener('click', function () {
    var collapsed = !layout.classList.contains('sidebar-collapsed');
    apply(collapsed);
    try { localStorage.setItem(STORAGE_KEY, collapsed ? '1' : '0'); } catch (e) {}
  });
})();

/* Blog post: auto-generate TOC from headings */
(function buildTOC() {
  const sidebar = document.querySelector('.toc-section ul');
  const content = document.querySelector('.blog-post-content');
  if (!sidebar || !content) return;

  const headings = content.querySelectorAll('h2, h3');
  headings.forEach((h, i) => {
    if (!h.id) h.id = 'section-' + i;
    const li = document.createElement('li');
    if (h.tagName === 'H3') li.classList.add('depth-3');
    const a = document.createElement('a');
    a.href = '#' + h.id;
    a.textContent = h.textContent;
    li.appendChild(a);
    sidebar.appendChild(li);
  });

  /* Scroll spy */
  const tocLinks = sidebar.querySelectorAll('a');
  const obs = new IntersectionObserver(entries => {
    entries.forEach(entry => {
      if (entry.isIntersecting) {
        tocLinks.forEach(l => l.classList.remove('active'));
        const active = sidebar.querySelector('a[href="#' + entry.target.id + '"]');
        if (active) active.classList.add('active');
      }
    });
  }, { rootMargin: '-80px 0px -60% 0px', threshold: 0 });

  headings.forEach(h => obs.observe(h));
})();


/* ===== Blog index: dynamic grid + category filter chips ===== */
(function buildBlogIndex() {
  var root = document.getElementById('blog-grid-root');
  if (!root || typeof BLOG_POSTS === 'undefined') return;

  var CATEGORY_META = {
    cpp:   { label: 'C++',   blurb: 'STL internals, concurrency, deep language mechanics.' },
    dsa:   { label: 'DSA',   blurb: 'Data structures and algorithms with animated walkthroughs.' },
    cp:    { label: 'CP',    blurb: 'Competitive programming math, techniques, and patterns.' },
    hld:   { label: 'HLD',   blurb: 'High-level system design: scale, storage, distribution.' },
    lld:   { label: 'LLD',   blurb: 'Low-level design: SOLID, patterns, interview walkthroughs.' },
    ml:    { label: 'ML',    blurb: 'Machine learning building blocks, from attention to transformers.' },
    mlops: { label: 'MLOps', blurb: 'Training infra, deployment, evaluation, observability for ML.' }
  };

  /* Build normalised post list: parse series breadcrumb into inner series name + Part tag. */
  var posts = [];
  Object.keys(BLOG_POSTS).forEach(function(file) {
    var p = BLOG_POSTS[file];
    var segs = p.series.split(/\s*&middot;\s*|\s*·\s*/).map(function(s){ return s.trim(); }).filter(Boolean);
    var catLabel = CATEGORY_META[p.category] ? CATEGORY_META[p.category].label : (segs[0] || p.category);
    var inner = segs.slice();
    if (inner[0] && inner[0].toLowerCase() === catLabel.toLowerCase()) inner.shift();
    var part = '';
    if (inner.length && /^Part\s+\d+/i.test(inner[inner.length - 1])) {
      part = inner.pop();
    }
    var seriesName = inner.join(' / ') || 'Singles';
    posts.push({
      file: file,
      href: 'blog/' + file,
      category: p.category,
      seriesName: seriesName,
      part: part,
      title: p.title,
      description: p.description,
      meta: p.meta
    });
  });

  /* Group: category -> series -> posts[] (preserve insertion order). */
  var byCategory = {};
  var catOrder = Object.keys(CATEGORY_META);
  posts.forEach(function(p) {
    if (!byCategory[p.category]) byCategory[p.category] = { seriesMap: {}, seriesOrder: [] };
    var cat = byCategory[p.category];
    if (!cat.seriesMap[p.seriesName]) {
      cat.seriesMap[p.seriesName] = [];
      cat.seriesOrder.push(p.seriesName);
    }
    cat.seriesMap[p.seriesName].push(p);
  });

  /* Chips: [all] [cpp · 7] [dsa · 62] ... */
  var chipsHost = document.getElementById('blog-chips');
  var statsHost = document.getElementById('blog-hero-stats');
  var activeCats = new Set();

  function makeChip(label, count, pressed, catCode) {
    var btn = document.createElement('button');
    btn.type = 'button';
    btn.className = 'blog-chip';
    btn.dataset.cat = catCode;
    btn.setAttribute('aria-pressed', pressed ? 'true' : 'false');
    btn.innerHTML = '<span class="blog-chip-label">' + label + '</span>' +
                    '<span class="blog-chip-count">' + count + '</span>';
    return btn;
  }

  chipsHost.appendChild(makeChip('all', posts.length, true, '__all__'));
  catOrder.forEach(function(code) {
    if (!byCategory[code]) return;
    var count = posts.filter(function(p){ return p.category === code; }).length;
    chipsHost.appendChild(makeChip(code, count, false, code));
  });

  if (statsHost) {
    var catCount = Object.keys(byCategory).length;
    var seriesCount = 0;
    Object.keys(byCategory).forEach(function(c){ seriesCount += byCategory[c].seriesOrder.length; });
    statsHost.textContent = posts.length + ' posts  ·  ' + seriesCount + ' series  ·  ' + catCount + ' topics';
  }

  /* Render all sections once. */
  var frag = document.createDocumentFragment();
  catOrder.forEach(function(code) {
    if (!byCategory[code]) return;
    var cat = byCategory[code];
    var catSection = document.createElement('section');
    catSection.className = 'blog-category';
    catSection.dataset.cat = code;

    var totalInCat = posts.filter(function(p){ return p.category === code; }).length;
    var header = document.createElement('div');
    header.className = 'blog-category-header';
    header.innerHTML =
      '<h2 class="blog-category-title">' +
        '<span class="mono blog-category-hash">##</span> ' + CATEGORY_META[code].label +
        '<span class="mono blog-category-count">[' + totalInCat + ']</span>' +
      '</h2>' +
      '<p class="blog-category-blurb">' + CATEGORY_META[code].blurb + '</p>';
    catSection.appendChild(header);

    cat.seriesOrder.forEach(function(sName) {
      var series = cat.seriesMap[sName];
      var details = document.createElement('details');
      details.className = 'blog-section';
      if (series.length <= 15) details.open = true;
      details.dataset.series = sName;

      var summary = document.createElement('summary');
      summary.className = 'blog-section-header';
      summary.innerHTML =
        '<span class="blog-section-chevron mono" aria-hidden="true">&#9656;</span>' +
        '<span class="blog-section-title">' + sName + '</span>' +
        '<span class="blog-section-count mono">' + series.length + '</span>';
      details.appendChild(summary);

      var grid = document.createElement('div');
      grid.className = 'blog-section-grid';
      series.forEach(function(p) {
        var card = document.createElement('a');
        card.className = 'blog-card';
        card.href = p.href;
        card.dataset.cat = p.category;

        var partHtml = p.part ? '<span class="blog-card-part mono">' + p.part + '</span>' : '';
        card.innerHTML =
          '<div class="blog-card-path mono">' + p.file + '</div>' +
          '<h3>' + p.title + '</h3>' +
          '<p>' + p.description + '</p>' +
          '<div class="blog-card-foot">' +
            '<span class="blog-card-meta mono">' + p.meta + '</span>' +
            partHtml +
          '</div>';
        grid.appendChild(card);
      });
      details.appendChild(grid);
      catSection.appendChild(details);
    });

    frag.appendChild(catSection);
  });
  root.appendChild(frag);

  /* Chip-only filtering. */
  function applyFilters() {
    var hasCats = activeCats.size > 0;
    root.querySelectorAll('.blog-category').forEach(function(catEl) {
      var match = !hasCats || activeCats.has(catEl.dataset.cat);
      catEl.classList.toggle('hidden', !match);
    });
  }

  chipsHost.addEventListener('click', function(e) {
    var btn = e.target.closest('.blog-chip');
    if (!btn) return;
    var cat = btn.dataset.cat;
    if (cat === '__all__') {
      activeCats.clear();
      chipsHost.querySelectorAll('.blog-chip').forEach(function(c) {
        c.setAttribute('aria-pressed', c.dataset.cat === '__all__' ? 'true' : 'false');
      });
    } else {
      if (activeCats.has(cat)) activeCats.delete(cat); else activeCats.add(cat);
      btn.setAttribute('aria-pressed', activeCats.has(cat) ? 'true' : 'false');
      var allBtn = chipsHost.querySelector('[data-cat="__all__"]');
      if (allBtn) allBtn.setAttribute('aria-pressed', activeCats.size === 0 ? 'true' : 'false');
    }
    applyFilters();
  });

  applyFilters();
})();
